                innov[k] = V_meas[k] - (3.0 + H*x_pred)
                x = np.clip(x_pred + K*innov[k], 0, 1)
                P = (1-K*H)*P_pred
                soc_kf[k] = x; K_hist[k] = K; P_hist[k] = P

